const contas = $('Buscar_Todas_Contas').all();
const fornecedoresAgregados = $('Consolidar_Fornecedores').first().json.fornecedores;

// Criar mapa de fornecedores por ID
const fornecedorMap = {};
for (const f of fornecedoresAgregados) {
  fornecedorMap[f.id] = f;
}

// Formatar dados para planilha
const resultado = contas.map(conta => {
  const c = conta.json;
  const fornecedor = c.fornecedor_id ? fornecedorMap[c.fornecedor_id] : null;

  // Determinar nome do fornecedor/beneficiário
  // Prioridade: fornecedor cadastrado > nome_cedente_original > fallbacks
  let nomeFornecedor = '';
  if (fornecedor && fornecedor.nome) {
    nomeFornecedor = fornecedor.nome;
  } else if (c.nome_cedente_original) {
    nomeFornecedor = c.nome_cedente_original;
  } else if (c.tipo_pagamento === 'boleto') {
    nomeFornecedor = c.nome_beneficiario_boleto || '';
  } else if (c.tipo_pagamento === 'concessionaria') {
    nomeFornecedor = c.descricao || 'Concessionária';
  }

  return {
    json: {
      ID: c.id,
      Fornecedor: nomeFornecedor,
      Tipo: c.tipo_pagamento,
      Valor: c.valor,
      Vencimento: c.vencimento,
      Status: c.status,
      Descricao: c.descricao || '',
      Codigo_Barras: c.codigo_barras || ''
    }
  };
});

return resultado;

const contasSupabase = $('Formatar_Dados_Planilha').all();
const planilhaAtual = $('Buscar_Planilha_Atual').all();

// Criar mapa da planilha atual por ID (tratando planilha vazia)
const planilhaMap = {};
const idsNaPlanilha = new Set();

if (planilhaAtual && planilhaAtual.length > 0) {
  for (const row of planilhaAtual) {
    if (row.json.ID) {
      // Se ID já existe no map, é duplicado na planilha - manter apenas o primeiro
      if (!planilhaMap[row.json.ID]) {
        planilhaMap[row.json.ID] = {
          ...row.json,
          row_number: row.json.row_number
        };
      }
      idsNaPlanilha.add(row.json.ID);
    }
  }
}

// Criar set de IDs do Supabase para comparação rápida
const idsSupabase = new Set();
for (const conta of contasSupabase) {
  if (conta.json.ID) {
    idsSupabase.add(conta.json.ID);
  }
}

const novos = [];
const atualizar = [];
const deletar = [];
const idsJaProcessados = new Set();

// Identificar novos e atualizações
for (const conta of contasSupabase) {
  const c = conta.json;

  // Evitar processar mesmo ID duas vezes
  if (idsJaProcessados.has(c.ID)) continue;
  idsJaProcessados.add(c.ID);

  const existente = planilhaMap[c.ID];

  if (!existente) {
    // Registro novo - adicionar com campo Pagar vazio
    novos.push({
      json: {
        ID: c.ID,
        Fornecedor: c.Fornecedor,
        Tipo: c.Tipo,
        Valor: c.Valor,
        Vencimento: c.Vencimento,
        Status: c.Status,
        Pagar: '',
        Descricao: c.Descricao,
        Codigo_Barras: c.Codigo_Barras || ''
      }
    });
  } else {
    // Verificar se precisa atualizar (comparar campos do Supabase)
    const mudou = (
      existente.Fornecedor !== c.Fornecedor ||
      existente.Tipo !== c.Tipo ||
      String(existente.Valor) !== String(c.Valor) ||
      existente.Vencimento !== c.Vencimento ||
      existente.Status !== c.Status ||
      existente.Descricao !== c.Descricao ||
      existente.Codigo_Barras !== c.Codigo_Barras
    );

    if (mudou) {
      atualizar.push({
        json: {
          ID: c.ID,
          Fornecedor: c.Fornecedor,
          Tipo: c.Tipo,
          Valor: c.Valor,
          Vencimento: c.Vencimento,
          Status: c.Status,
          Pagar: existente.Pagar || '',
          Descricao: c.Descricao,
          Codigo_Barras: c.Codigo_Barras || ''
        }
      });
    }
  }
}

// Identificar registros a deletar (estão na planilha mas não no Supabase)
const idsParaDeletar = new Set();
for (const id of Object.keys(planilhaMap)) {
  if (!idsSupabase.has(id)) {
    idsParaDeletar.add(id);
    deletar.push({
      json: {
        ID: id,
        row_number: planilhaMap[id].row_number
      }
    });
  }
}

// Ordenar deletar por row_number decrescente
deletar.sort((a, b) => b.json.row_number - a.json.row_number);

return [
  {
    json: {
      novos: novos.map(n => n.json),
      atualizar: atualizar.map(a => a.json),
      deletar: deletar.map(d => d.json),
      qtd_novos: novos.length,
      qtd_atualizar: atualizar.length,
      qtd_deletar: deletar.length
    }
  }
];

const dados = $('Comparar_Dados').first().json;

if (dados.novos.length === 0) {
  return [];
}

return dados.novos.map(item => ({ json: item }));

const dados = $('Comparar_Dados').first().json;

if (dados.atualizar.length === 0) {
  return [];
}

return dados.atualizar.map(item => ({ json: item }));

const dados = $input.first().json;
const deletar = dados.deletar || [];

if (deletar.length === 0) {
  return [];
}

return deletar.map(item => ({ json: item }));

// Pega o timestamp atual
const agora = Date.now();

// Verifica se há uma variável global com o último processamento
const ultimoProcessamento = $execution.customData.get('ultimo_sync') || 0;

// Se processou nos últimos 8 segundos, cancela
if (agora - ultimoProcessamento < 8000) {
  return []; // Retorna vazio para não continuar
}

// Salva o timestamp atual
$execution.customData.set('ultimo_sync', agora);

// Continua com o item
return $input.all();

